import org.apache.commons.text.StringEscapeUtils;
import java.util.Scanner;

public class SecureXSSExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Escape user input to prevent XSS attacks
        String escapedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Generating greeting message with properly escaped user input
        String greetingMessage = "Hello, " + escapedUserInput + "!";

        // Displaying the greeting message with properly escaped user input
        System.out.println(greetingMessage);
    }
}

